const fs = require('fs');
const path = require('path');

// ============== ELF Loader ==============
function loadELF(filepath) {
  const data = fs.readFileSync(filepath);
  // Verify ELF magic
  if (data[0] !== 0x7f || data[1] !== 0x45 || data[2] !== 0x4c || data[3] !== 0x46) {
    throw new Error('Not an ELF file');
  }
  const isLE = data[5] === 1;
  const r = (off, sz) => {
    let v = 0;
    for (let i = 0; i < sz; i++) v |= data[off + i] << (i * 8);
    return v >>> 0;
  };
  const entry = r(0x18, 4);
  const phoff = r(0x1c, 4);
  const phnum = r(0x2c, 2);
  const phentsize = r(0x2a, 2);
  const segments = [];
  for (let i = 0; i < phnum; i++) {
    const off = phoff + i * phentsize;
    const type = r(off, 4);
    if (type !== 1) continue; // PT_LOAD
    const offset = r(off + 4, 4);
    const vaddr = r(off + 8, 4);
    const filesz = r(off + 16, 4);
    const memsz = r(off + 20, 4);
    const flags = r(off + 24, 4);
    segments.push({ offset, vaddr, filesz, memsz, flags });
  }
  return { entry, segments, data };
}

// ============== Memory ==============
class Memory {
  constructor() {
    this.pages = new Map();
    this.pageSize = 4096;
  }

  _key(addr) { return (addr >>> 12) >>> 0; }
  _off(addr) { return addr & 0xfff; }

  _getPage(addr, write = false) {
    const key = this._key(addr);
    let page = this.pages.get(key);
    if (!page) {
      page = Buffer.alloc(this.pageSize);
      this.pages.set(key, page);
    }
    return page;
  }

  read8(addr) {
    addr = addr >>> 0;
    const page = this._getPage(addr);
    return page[this._off(addr)];
  }

  read16(addr) {
    addr = addr >>> 0;
    const lo = this.read8(addr);
    const hi = this.read8(addr + 1);
    return (lo | (hi << 8)) >>> 0;
  }

  read32(addr) {
    addr = addr >>> 0;
    const page = this._getPage(addr);
    const off = this._off(addr);
    if (off <= 4093) {
      return (page[off] | (page[off+1] << 8) | (page[off+2] << 16) | ((page[off+3] << 24) >>> 0)) >>> 0;
    }
    const b0 = this.read8(addr);
    const b1 = this.read8(addr + 1);
    const b2 = this.read8(addr + 2);
    const b3 = this.read8(addr + 3);
    return (b0 | (b1 << 8) | (b2 << 16) | ((b3 << 24) >>> 0)) >>> 0;
  }

  write8(addr, val) {
    addr = addr >>> 0;
    const page = this._getPage(addr, true);
    page[this._off(addr)] = val & 0xff;
  }

  write16(addr, val) {
    addr = addr >>> 0;
    this.write8(addr, val & 0xff);
    this.write8(addr + 1, (val >>> 8) & 0xff);
  }

  write32(addr, val) {
    addr = addr >>> 0;
    const page = this._getPage(addr, true);
    const off = this._off(addr);
    if (off <= 4093) {
      page[off] = val & 0xff;
      page[off+1] = (val >>> 8) & 0xff;
      page[off+2] = (val >>> 16) & 0xff;
      page[off+3] = (val >>> 24) & 0xff;
      return;
    }
    this.write8(addr, val & 0xff);
    this.write8(addr + 1, (val >>> 8) & 0xff);
    this.write8(addr + 2, (val >>> 16) & 0xff);
    this.write8(addr + 3, (val >>> 24) & 0xff);
  }

  readString(addr) {
    const bytes = [];
    let a = addr >>> 0;
    while (true) {
      const b = this.read8(a++);
      if (b === 0) break;
      bytes.push(b);
      if (bytes.length > 4096) break;
    }
    return Buffer.from(bytes).toString('utf8');
  }

  loadSegment(vaddr, data, offset, filesz, memsz) {
    for (let i = 0; i < filesz; i++) {
      this.write8(vaddr + i, data[offset + i]);
    }
    // BSS is zero-filled by Buffer.alloc
  }
}

// ============== Syscall Numbers (x86_64 Linux) ==============
const SYS = {
  read: 0, write: 1, open: 2, close: 3, lseek: 8,
  brk: 12, exit: 60, fsync: 74, rename: 82, mkdir: 83, unlink: 87,
  time: 201
};

// ============== Open Flags ==============
function translateFlags(f) {
  const O_RDONLY = 0, O_WRONLY = 1, O_RDWR = 2;
  const O_CREAT = 64, O_TRUNC = 512, O_APPEND = 1024;
  let flags = '';
  const access = f & 7;
  if (access === O_RDONLY) flags = 'r';
  else if (access === O_WRONLY) flags = 'w';
  else if (access === O_RDWR) flags = 'r+';
  if (f & O_CREAT) {
    if (flags === 'r+') flags = 'w+';
    else flags = flags;
  }
  if (f & O_TRUNC) {
    if (flags.includes('r+')) flags = 'w+';
    else if (flags === 'r') flags = 'w';
  }
  if (f & O_APPEND) {
    flags = flags.replace('r', 'a').replace('w', 'a');
    if (!flags.includes('a')) flags = 'a' + flags;
  }
  return flags;
}

// ============== CPU ==============
class MIPSCPU {
  constructor(mem, entry) {
    this.mem = mem;
    this.pc = entry >>> 0;
    this.nextPC = (entry + 4) >>> 0;
    this.regs = new Int32Array(32);
    this.uregs = new Uint32Array(this.regs.buffer);
    this.hi = 0;
    this.lo = 0;
    this.delaySlot = false;
    this.delaySlotPC = 0;
    this.exitCode = null;
    this.instructionCount = 0;

    // File descriptors
    this.fdMap = new Map();
    this.nextFd = 3;
    // stdin, stdout, stderr
    this.fdMap.set(0, { type: 'stdio', fd: 0 });
    this.fdMap.set(1, { type: 'stdio', fd: 1 });
    this.fdMap.set(2, { type: 'stdio', fd: 2 });

    // Heap
    this.heapEnd = 0;
  }

  r(idx) { return this.uregs[idx] >>> 0; }
  sr(idx) { return this.regs[idx]; }
  w(idx, val) {
    if (idx === 0) return;
    this.uregs[idx] = val >>> 0;
  }

  run() {
    while (this.exitCode === null) {
      this.step();
    }
    return this.exitCode;
  }

  step() {
    const pc = this.pc;
    const instr = this.mem.read32(pc);
    this.pc = this.nextPC;
    this.nextPC = (this.nextPC + 4) >>> 0;
    this.execute(instr, pc);
    this.regs[0] = 0;
    this.instructionCount++;
  }

  execute(instr, pc) {
    const op = (instr >>> 26) & 0x3f;
    const rs = (instr >>> 21) & 0x1f;
    const rt = (instr >>> 16) & 0x1f;
    const rd = (instr >>> 11) & 0x1f;
    const shamt = (instr >>> 6) & 0x1f;
    const funct = instr & 0x3f;
    const imm16 = instr & 0xffff;
    const simm16 = (imm16 << 16) >> 16;
    const imm26 = instr & 0x3ffffff;

    switch (op) {
      case 0x00: this.executeSpecial(funct, rs, rt, rd, shamt, instr); break;
      case 0x01: this.executeRegimm(rs, rt, simm16); break;
      case 0x02: // j
        this.nextPC = ((pc + 4) & 0xf0000000) | (imm26 << 2);
        break;
      case 0x03: // jal
        this.w(31, (pc + 8) >>> 0);
        this.nextPC = ((pc + 4) & 0xf0000000) | (imm26 << 2);
        break;
      case 0x04: // beq
        if (this.r(rs) === this.r(rt)) this.nextPC = (pc + 4 + (simm16 << 2)) >>> 0;
        break;
      case 0x05: // bne
        if (this.r(rs) !== this.r(rt)) this.nextPC = (pc + 4 + (simm16 << 2)) >>> 0;
        break;
      case 0x06: // blez
        if (this.sr(rs) <= 0) this.nextPC = (pc + 4 + (simm16 << 2)) >>> 0;
        break;
      case 0x07: // bgtz
        if (this.sr(rs) > 0) this.nextPC = (pc + 4 + (simm16 << 2)) >>> 0;
        break;
      case 0x08: // addi (with overflow, but we ignore trap)
      case 0x09: // addiu
        this.w(rt, (this.r(rs) + simm16) >>> 0);
        break;
      case 0x0a: // slti
        this.w(rt, this.sr(rs) < simm16 ? 1 : 0);
        break;
      case 0x0b: // sltiu
        this.w(rt, (this.r(rs) >>> 0) < (simm16 >>> 0) ? 1 : 0);
        break;
      case 0x0c: // andi
        this.w(rt, this.r(rs) & imm16);
        break;
      case 0x0d: // ori
        this.w(rt, this.r(rs) | imm16);
        break;
      case 0x0e: // xori
        this.w(rt, this.r(rs) ^ imm16);
        break;
      case 0x0f: // lui
        this.w(rt, (imm16 << 16) >>> 0);
        break;
      case 0x10: case 0x11: case 0x12: case 0x13: case 0x14: case 0x15: case 0x16: case 0x17:
        // COPn - ignore
        break;
      case 0x1c: this.executeSpecial2(rs, rt, rd, shamt, funct, instr); break;
      case 0x1f: this.executeSpecial3(rs, rt, rd, shamt, funct, instr); break;
      case 0x20: // lb
        this.w(rt, ((this.mem.read8((this.r(rs) + simm16) >>> 0)) << 24) >> 24);
        break;
      case 0x21: // lh
        {
          const addr = (this.r(rs) + simm16) >>> 0;
          this.w(rt, ((this.mem.read16(addr)) << 16) >> 16);
        }
        break;
      case 0x22: // lwl
        {
          const addr = (this.r(rs) + simm16) >>> 0;
          const aligned = addr & ~3;
          const byteOff = addr & 3;
          const old = this.r(rt);
          const memVal = this.mem.read32(aligned);
          let result;
          // Little-endian lwl: load leftmost bytes
          switch (byteOff) {
            case 0: result = memVal; break;
            case 1: result = (old & 0xff000000) | (memVal >>> 8); break;
            case 2: result = (old & 0xffff0000) | (memVal >>> 16); break;
            case 3: result = (old & 0xffffff00) | (memVal >>> 24); break;
          }
          this.w(rt, result >>> 0);
        }
        break;
      case 0x23: // lw
        this.w(rt, this.mem.read32((this.r(rs) + simm16) >>> 0));
        break;
      case 0x24: // lbu
        this.w(rt, this.mem.read8((this.r(rs) + simm16) >>> 0));
        break;
      case 0x25: // lhu
        this.w(rt, this.mem.read16((this.r(rs) + simm16) >>> 0));
        break;
      case 0x26: // lwr
        {
          const addr = (this.r(rs) + simm16) >>> 0;
          const aligned = addr & ~3;
          const byteOff = addr & 3;
          const old = this.r(rt);
          const memVal = this.mem.read32(aligned);
          let result;
          // Little-endian lwr: load rightmost bytes
          switch (byteOff) {
            case 0: result = (old & 0x00ffffff) | (memVal << 24); break;
            case 1: result = (old & 0x0000ffff) | (memVal << 16); break;
            case 2: result = (old & 0x000000ff) | (memVal << 8); break;
            case 3: result = memVal; break;
          }
          this.w(rt, result >>> 0);
        }
        break;
      case 0x28: // sb
        this.mem.write8((this.r(rs) + simm16) >>> 0, this.r(rt));
        break;
      case 0x29: // sh
        this.mem.write16((this.r(rs) + simm16) >>> 0, this.r(rt));
        break;
      case 0x2a: // swl
        {
          const addr = (this.r(rs) + simm16) >>> 0;
          const aligned = addr & ~3;
          const byteOff = addr & 3;
          const old = this.mem.read32(aligned);
          const val = this.r(rt);
          let result;
          switch (byteOff) {
            case 0: result = val; break;
            case 1: result = (old & 0xff000000) | (val & 0x00ffffff); break;
            case 2: result = (old & 0xffff0000) | (val & 0x0000ffff); break;
            case 3: result = (old & 0xffffff00) | (val & 0x000000ff); break;
          }
          this.mem.write32(aligned, result >>> 0);
        }
        break;
      case 0x2b: // sw
        this.mem.write32((this.r(rs) + simm16) >>> 0, this.r(rt));
        break;
      case 0x2e: // swr
        {
          const addr = (this.r(rs) + simm16) >>> 0;
          const aligned = addr & ~3;
          const byteOff = addr & 3;
          const old = this.mem.read32(aligned);
          const val = this.r(rt);
          let result;
          switch (byteOff) {
            case 0: result = (old & 0x00ffffff) | (val << 24); break;
            case 1: result = (old & 0x0000ffff) | (val << 16); break;
            case 2: result = (old & 0x000000ff) | (val << 8); break;
            case 3: result = val; break;
          }
          this.mem.write32(aligned, result >>> 0);
        }
        break;
      case 0x30: // lwc1
      case 0x31: case 0x32: case 0x33: case 0x34: case 0x35: case 0x36: case 0x37:
      case 0x38: case 0x39: case 0x3a: case 0x3b: case 0x3c: case 0x3d: case 0x3e: case 0x3f:
        // FPU load/store - we ignore FPU for now
        break;
      default:
        console.error(`Unimplemented opcode 0x${op.toString(16)} at PC=0x${pc.toString(16)}, instr=0x${instr.toString(16).padStart(8,'0')}`);
        process.exit(1);
    }
  }

  executeSpecial(funct, rs, rt, rd, shamt, instr) {
    switch (funct) {
      case 0x00: // sll
        this.w(rd, (this.r(rt) << shamt) >>> 0);
        break;
      case 0x02: // srl
        this.w(rd, this.r(rt) >>> shamt);
        break;
      case 0x03: // sra
        this.w(rd, this.sr(rt) >> shamt);
        break;
      case 0x04: // sllv
        this.w(rd, (this.r(rt) << (this.r(rs) & 0x1f)) >>> 0);
        break;
      case 0x06: // srlv
        this.w(rd, this.r(rt) >>> (this.r(rs) & 0x1f));
        break;
      case 0x07: // srav
        this.w(rd, this.sr(rt) >> (this.r(rs) & 0x1f));
        break;
      case 0x08: // jr
        this.nextPC = this.r(rs);
        break;
      case 0x09: // jalr
        {
          const target = this.r(rs);
          this.w(rd || 31, (this.pc + 8) >>> 0);
          this.nextPC = target;
        }
        break;
      case 0x0a: // movz
        if (this.r(rt) === 0) this.w(rd, this.r(rs));
        break;
      case 0x0b: // movn
        if (this.r(rt) !== 0) this.w(rd, this.r(rs));
        break;
      case 0x0c: // syscall
        this.handleSyscall();
        break;
      case 0x0d: // break
        console.error('BREAK instruction');
        process.exit(1);
        break;
      case 0x0f: // sync
        break;
      case 0x10: // mfhi
        this.w(rd, this.hi);
        break;
      case 0x11: // mthi
        this.hi = this.r(rs);
        break;
      case 0x12: // mflo
        this.w(rd, this.lo);
        break;
      case 0x13: // mtlo
        this.lo = this.r(rs);
        break;
      case 0x18: // mult
        {
          const a = BigInt(this.sr(rs));
          const b = BigInt(this.sr(rt));
          const result = a * b;
          this.lo = Number(result & 0xffffffffn) >>> 0;
          this.hi = Number((result >> 32n) & 0xffffffffn) >>> 0;
        }
        break;
      case 0x19: // multu
        {
          const a = BigInt(this.r(rs));
          const b = BigInt(this.r(rt));
          const result = a * b;
          this.lo = Number(result & 0xffffffffn) >>> 0;
          this.hi = Number((result >> 32n) & 0xffffffffn) >>> 0;
        }
        break;
      case 0x1a: // div
        {
          let a = this.sr(rs);
          let b = this.sr(rt);
          if (b !== 0) {
            this.lo = (Math.trunc(a / b)) >>> 0;
            this.hi = (a % b) >>> 0;
          }
        }
        break;
      case 0x1b: // divu
        {
          const a = this.r(rs);
          const b = this.r(rt);
          if (b !== 0) {
            this.lo = (Math.floor(a / b)) >>> 0;
            this.hi = (a % b) >>> 0;
          }
        }
        break;
      case 0x20: // add
      case 0x21: // addu
        this.w(rd, (this.r(rs) + this.r(rt)) >>> 0);
        break;
      case 0x22: // sub
      case 0x23: // subu
        this.w(rd, (this.r(rs) - this.r(rt)) >>> 0);
        break;
      case 0x24: // and
        this.w(rd, this.r(rs) & this.r(rt));
        break;
      case 0x25: // or
        this.w(rd, this.r(rs) | this.r(rt));
        break;
      case 0x26: // xor
        this.w(rd, this.r(rs) ^ this.r(rt));
        break;
      case 0x27: // nor
        this.w(rd, ~(this.r(rs) | this.r(rt)) >>> 0);
        break;
      case 0x2a: // slt
        this.w(rd, this.sr(rs) < this.sr(rt) ? 1 : 0);
        break;
      case 0x2b: // sltu
        this.w(rd, (this.r(rs) >>> 0) < (this.r(rt) >>> 0) ? 1 : 0);
        break;
      case 0x30: // tge - trap
        break;
      case 0x34: // teq
        break;
      case 0x36: // tne
        break;
      default:
        console.error(`Unimplemented SPECIAL funct 0x${funct.toString(16)} at PC=0x${this.pc.toString(16)}`);
        process.exit(1);
    }
  }

  executeRegimm(rs, rt, simm16) {
    const subop = rt;
    const target = (this.pc + (simm16 << 2)) >>> 0;
    switch (subop) {
      case 0x00: // bltz
        if (this.sr(rs) < 0) this.nextPC = target;
        break;
      case 0x01: // bgez
        if (this.sr(rs) >= 0) this.nextPC = target;
        break;
      case 0x10: // bltzal
        this.w(31, (this.pc + 8) >>> 0);
        if (this.sr(rs) < 0) this.nextPC = target;
        break;
      case 0x11: // bgezal
        this.w(31, (this.pc + 8) >>> 0);
        if (this.sr(rs) >= 0) this.nextPC = target;
        break;
      default:
        console.error(`Unimplemented REGIMM subop 0x${subop.toString(16)} at PC=0x${this.pc.toString(16)}`);
        process.exit(1);
    }
  }

  executeSpecial2(rs, rt, rd, shamt, funct, instr) {
    switch (funct) {
      case 0x02: // mul (MIPS32)
        this.w(rd, (Math.imul(this.r(rs), this.r(rt))) >>> 0);
        break;
      case 0x00: // madd
        {
          let a = BigInt(this.sr(rs));
          let b = BigInt(this.sr(rt));
          let acc = (BigInt(this.hi) << 32n) | BigInt(this.lo);
          acc += a * b;
          this.lo = Number(acc & 0xffffffffn) >>> 0;
          this.hi = Number((acc >> 32n) & 0xffffffffn) >>> 0;
        }
        break;
      case 0x01: // maddu
        {
          let a = BigInt(this.r(rs));
          let b = BigInt(this.r(rt));
          let acc = (BigInt(this.hi) << 32n) | BigInt(this.lo);
          acc += a * b;
          this.lo = Number(acc & 0xffffffffn) >>> 0;
          this.hi = Number((acc >> 32n) & 0xffffffffn) >>> 0;
        }
        break;
      case 0x20: // clz
        {
          const val = this.r(rs);
          this.w(rd, val === 0 ? 32 : Math.clz32(val));
        }
        break;
      case 0x21: // clo
        {
          const val = ~this.r(rs) >>> 0;
          this.w(rd, val === 0 ? 32 : Math.clz32(val));
        }
        break;
      default:
        console.error(`Unimplemented SPECIAL2 funct 0x${funct.toString(16)} at PC=0x${this.pc.toString(16)}`);
        process.exit(1);
    }
  }

  executeSpecial3(rs, rt, rd, shamt, funct, instr) {
    switch (funct) {
      case 0x00: // ext
        {
          const pos = shamt;
          const size = rd + 1;
          const mask = (1 << size) - 1;
          this.w(rt, (this.r(rs) >>> pos) & mask);
        }
        break;
      case 0x04: // ins
        {
          const pos = shamt;
          const size = rd + 1 - pos;
          const mask = ((1 << size) - 1) << pos;
          this.w(rt, (this.r(rt) & ~mask) | ((this.r(rs) << pos) & mask));
        }
        break;
      case 0x20: // bshfl
        {
          const bshfl_op = shamt;
          switch (bshfl_op) {
            case 0x02: // wsbh
              {
                const v = this.r(rt);
                this.w(rd, (((v & 0x00ff00ff) << 8) | ((v & 0xff00ff00) >>> 8)) >>> 0);
              }
              break;
            case 0x16: // seb
              this.w(rd, ((this.r(rt) & 0xff) << 24) >> 24);
              break;
            case 0x18: // seh
              this.w(rd, ((this.r(rt) & 0xffff) << 16) >> 16);
              break;
            default:
              console.error(`Unimplemented BSHFL 0x${bshfl_op.toString(16)}`);
              process.exit(1);
          }
        }
        break;
      case 0x3b: // rdhwr
        // Just return 0 for any HWR register
        this.w(rt, 0);
        break;
      default:
        console.error(`Unimplemented SPECIAL3 funct 0x${funct.toString(16)} at PC=0x${this.pc.toString(16)}`);
        process.exit(1);
    }
  }

  // ============== Syscall Handler ==============
  handleSyscall() {
    const syscallNum = this.r(2); // $v0
    const a0 = this.r(4);
    const a1 = this.r(5);
    const a2 = this.r(6);
    const a3 = this.r(7);

    switch (syscallNum) {
      case SYS.read: {
        const fd = a0;
        const buf = a1;
        const count = a2;
        const entry = this.fdMap.get(fd);
        if (!entry) {
          this.w(2, -1 >>> 0);
          break;
        }
        if (entry.type === 'stdio') {
          if (fd === 0) {
            // stdin - return 0 (no data)
            this.w(2, 0);
          } else {
            this.w(2, 0);
          }
        } else if (entry.type === 'file') {
          const data = Buffer.alloc(count);
          try {
            const bytesRead = fs.readSync(entry.hostFd, data, 0, count, entry.position);
            for (let i = 0; i < bytesRead; i++) {
