// ============== Main ==============
function main() {
  console.log('Loading ELF...');
  const elf = loadELF('/app/doomgeneric_mips');
  console.log(`Entry point: 0x${elf.entry.toString(16)}`);

  const mem = new Memory();

  // Load segments
  for (const seg of elf.segments) {
    console.log(`Loading segment: vaddr=0x${seg.vaddr.toString(16)} filesz=${seg.filesz} memsz=${seg.memsz}`);
    mem.loadSegment(seg.vaddr, elf.data, seg.offset, seg.filesz, seg.memsz);
  }

  // Set up stack
  const STACK_TOP = 0x7fff0000;
  const STACK_SIZE = 0x100000; // 1MB
  for (let i = 0; i < STACK_SIZE; i += 4) {
    mem.write32(STACK_TOP - STACK_SIZE + i, 0);
  }

  // Set up heap (after BSS)
  const BSS_END = 0x4750c0 + 0x4003c6d0;
  const HEAP_START = (BSS_END + 0xfff) & ~0xfff;

  console.log(`Stack: 0x${(STACK_TOP - STACK_SIZE).toString(16)} - 0x${STACK_TOP.toString(16)}`);
  console.log(`Heap start: 0x${HEAP_START.toString(16)}`);

  // Initialize CPU
  const cpu = new MIPSCPU(mem, elf.entry);
  cpu.uregs[29] = STACK_TOP; // $sp
  cpu.uregs[28] = 0; // $gp - not used
  cpu.heapEnd = HEAP_START;

  // Create /tmp directory if it doesn't exist
  try { fs.mkdirSync('/tmp', { recursive: true }); } catch (e) {}

  console.log('Starting execution...');
  const startTime = Date.now();
  const exitCode = cpu.run();
  const elapsed = (Date.now() - startTime) / 1000;
  console.log(`\nExited with code ${exitCode}`);
  console.log(`Instructions executed: ${cpu.instructionCount}`);
  console.log(`Time: ${elapsed.toFixed(2)}s`);
  console.log(`Speed: ${Math.floor(cpu.instructionCount / elapsed)} insns/sec`);
}

